// Compute search matches reactively. Empty query → null (don't render results).
search_matches = (() =&gt; {
  const q = (search_query || "").trim().toLowerCase()
  if (q.length &lt; 1) return null
  const tokens = q.split(/\s+/).filter(t =&gt; t.length &gt; 0)
  return etf_search_index.filter(d =&gt; tokens.every(t =&gt; d.haystack.includes(t)))
})()









